import{_ as a,o as t,c as s,a2 as o}from"./chunks/framework.D5wUhsuj.js";const i="/docs/assets/r-studio-spawner.CW0qHafu.png",r="/docs/assets/r-studio-screen-home.5KwgWwqj.png",g=JSON.parse('{"title":"RStudio","description":"","frontmatter":{},"headers":[],"relativePath":"labs/rstudio.md","filePath":"labs/rstudio.md","lastUpdated":1783462398000}'),n={name:"labs/rstudio.md"};function l(d,e,c,u,p,m){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="rstudio" tabindex="-1">RStudio <a class="header-anchor" href="#rstudio" aria-label="Permalink to &quot;RStudio&quot;">​</a></h1><p>RStudio Labs provide a browser-based R development environment inside a prokube workspace.</p><div class="info custom-block"><p class="custom-block-title">RStudio documentation</p><p>Upstream reference: <a href="https://docs.posit.co/ide/user/" target="_blank" rel="noreferrer">RStudio documentation</a></p></div><p>Use RStudio when your workflow is centered around R packages, statistical analysis, reports, or notebooks that benefit from an R-native IDE.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Create an RStudio Lab from the Labs page. The launch dialog uses the same basic options as other Labs: name, image, compute resources, storage, configurations, and security options.</p><p><img src="'+i+'" alt="Launch RStudio Lab" loading="lazy"></p><p>The selected image defines the R version, installed R packages, system libraries, and command-line tools available when the Lab starts.</p><p><img src="'+r+'" alt="RStudio Lab home screen" loading="lazy"></p><h2 id="common-uses" tabindex="-1">Common Uses <a class="header-anchor" href="#common-uses" aria-label="Permalink to &quot;Common Uses&quot;">​</a></h2><ul><li>Exploratory data analysis with R.</li><li>Statistical modeling and visualization.</li><li>R Markdown and report generation.</li><li>Accessing workspace storage and platform services from R code.</li></ul><p>RStudio uses the same persistence, object-storage, and image-building model as other Labs. See <a href="./">Using Labs</a> for shared workspace, storage, package-installation, and BuildKit details.</p><p>For controlled R package stacks or additional system libraries, use a custom image. prokube can also support custom Lab solutions when the standard images do not fit your team&#39;s requirements.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./">Using Labs</a></li><li><a href="./custom_notebooks.html">Custom Notebooks</a></li><li><a href="https://docs.prokube.ai/latest/" target="_blank" rel="noreferrer">Existing documentation</a></li></ul>',15)])])}const b=a(n,[["render",l]]);export{g as __pageData,b as default};
